import java.io.File;
import java.io.FileInputStream;
import java.util.HashMap;
import java.util.Map;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;

public class XMLConfigParser {

    public Map<String, String> parseConfigFile(File configFile) throws Exception {
        Map<String, String> configMap = new HashMap<>();

        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(new FileInputStream(configFile));

        Element rootElement = document.getDocumentElement();
        parseNode(rootElement, configMap);

        return configMap;
    }

    private void parseNode(Node node, Map<String, String> configMap) {
        if (node.getNodeType() == Node.ELEMENT_NODE) {
            Element element = (Element) node;
            String key = element.getAttribute("key");
            String value = element.getAttribute("value");

            configMap.put(key, value);

            for (Node childNode : element.getChildNodes()) {
                parseNode(childNode, configMap);
            }
        }
    }
}